import {normalizedComments} from '../fixtures'
import {ADD_COMMENT} from '../types'

export default function (state = arrToMap(normalizedComments), action) {
    switch (action.type) {
        case ADD_COMMENT:
            return {
                ...state,
                
            }
        default:
            return state
    }
}
